import React from "react";

const Inflation = () => {

  const data = [
    { month: "Jan", loss: 1200 },
    { month: "Feb", loss: 1400 },
    { month: "Mar", loss: 1800 },
    { month: "Apr", loss: 2000 },
    { month: "May", loss: 2500 },
    { month: "Jun", loss: 2700 }
  ];

  return (
    <div>
      <h2>Inflation Loss</h2>

      <table className="data-table">

        <thead>
          <tr>
            <th>Month</th>
            <th>Inflation Loss</th>
          </tr>
        </thead>

        <tbody>

          {data.map((item, index) => (
            <tr key={index}>
              <td>{item.month}</td>
              <td>₹{item.loss}</td>
            </tr>
          ))}

        </tbody>

      </table>
    </div>
  );
};

export default Inflation;
